{
  "name": "Nha Trang Group Trip Manager",
  "description": "A real-time itinerary and expense sharing app for group travel to Nha Trang, featuring currency conversion, N-way splitting, and resort activity tracking.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  ACCOMMODATION = '숙박',
  TRANSPORT = '교통',
  FOOD = '식음료',
  SHOPPING = '쇼핑',
  ALCOHOL = '음주',
  OTHER = '기타'
}

export enum Currency {
  VND = 'VND',
  KRW = 'KRW'
}

export interface Expense {
  id: string;
  description: string;
  category: Category;
  amount: number;
  currency: Currency;
  timestamp: number;
  createdBy: string;
}

export interface Activity {
  id: string;
  time: string;
  description: string;
  isPaid?: boolean;
  requiresBooking?: boolean;
}

export interface DaySchedule {
  id: string;
  date: string;
  dayName: string;
  title: string;
  timeline: Activity[];
  resortProgram?: Activity[];
}

export type TabType = 'itinerary' | 'expenses' | 'info';

export interface User {
  id: string;
  name: string;
}

import React, { useState, useEffect, useCallback } from 'react';
import { TabType, Expense, User, DaySchedule } from './types';
import { INITIAL_ITINERARY, GROUP_SIZE } from './constants';
import Header from './components/Header';
import Navigation from './components/Navigation';
import ItineraryTab from './tabs/ItineraryTab';
import ExpenseTab from './tabs/ExpenseTab';
import InfoTab from './tabs/InfoTab';
import Login from './components/Login';

// Simulate real-time sync with BroadcastChannel
const syncChannel = new BroadcastChannel('trip_sync_channel');

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('itinerary');
  const [user, setUser] = useState<User | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [itinerary, setItinerary] = useState<DaySchedule[]>(INITIAL_ITINERARY);

  // Load from localStorage
  useEffect(() => {
    const savedExpenses = localStorage.getItem('trip_expenses');
    const savedItinerary = localStorage.getItem('trip_itinerary');
    const savedUser = localStorage.getItem('trip_user');

    if (savedExpenses) setExpenses(JSON.parse(savedExpenses));
    if (savedItinerary) setItinerary(JSON.parse(savedItinerary));
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  // Sync listener
  useEffect(() => {
    const handleSync = (event: MessageEvent) => {
      if (event.data.type === 'SYNC_EXPENSES') {
        setExpenses(event.data.payload);
      } else if (event.data.type === 'SYNC_ITINERARY') {
        setItinerary(event.data.payload);
      }
    };
    syncChannel.addEventListener('message', handleSync);
    return () => syncChannel.removeEventListener('message', handleSync);
  }, []);

  const saveExpenses = useCallback((newExpenses: Expense[]) => {
    setExpenses(newExpenses);
    localStorage.setItem('trip_expenses', JSON.stringify(newExpenses));
    syncChannel.postMessage({ type: 'SYNC_EXPENSES', payload: newExpenses });
  }, []);

  const saveItinerary = useCallback((newItinerary: DaySchedule[]) => {
    setItinerary(newItinerary);
    localStorage.setItem('trip_itinerary', JSON.stringify(newItinerary));
    syncChannel.postMessage({ type: 'SYNC_ITINERARY', payload: newItinerary });
  }, []);

  const handleLogin = (name: string) => {
    const newUser = { id: Math.random().toString(36).substr(2, 9), name };
    setUser(newUser);
    localStorage.setItem('trip_user', JSON.stringify(newUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('trip_user');
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex flex-col min-h-screen bg-slate-50 max-w-md mx-auto relative shadow-xl overflow-hidden">
      <Header onLogout={handleLogout} />

      <main className="flex-1 overflow-y-auto pb-24 no-scrollbar">
        {activeTab === 'itinerary' && (
          <ItineraryTab 
            itinerary={itinerary} 
            onUpdate={saveItinerary} 
          />
        )}
        {activeTab === 'expenses' && (
          <ExpenseTab 
            expenses={expenses} 
            onUpdate={saveExpenses} 
            user={user}
          />
        )}
        {activeTab === 'info' && (
          <InfoTab />
        )}
      </main>

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
    </div>
  );
};

export default App;

import React from 'react';
import { LogOut, Calendar, Users, MapPin } from 'lucide-react';

interface HeaderProps {
  onLogout: () => void;
}

const Header: React.FC<HeaderProps> = ({ onLogout }) => {
  return (
    <div className="bg-indigo-600 text-white p-5 rounded-b-[2.5rem] shadow-lg sticky top-0 z-20">
      <div className="flex justify-between items-start mb-3">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">AAPK 나트랑 여행</h1>
          <p className="text-indigo-100 text-sm flex items-center gap-1 mt-1 opacity-90">
            <MapPin size={14} /> 멜리아 빈펄 리조트 (The Level)
          </p>
        </div>
        <button 
          onClick={onLogout}
          className="p-2 bg-indigo-500/30 rounded-full hover:bg-indigo-500/50 transition-colors"
        >
          <LogOut size={18} />
        </button>
      </div>

      <div className="flex gap-4 mt-4">
        <div className="flex items-center gap-2 bg-indigo-500/30 px-3 py-1.5 rounded-xl border border-indigo-400/20">
          <Calendar size={16} />
          <span className="text-sm font-medium">3/20 - 3/23</span>
        </div>
        <div className="flex items-center gap-2 bg-indigo-500/30 px-3 py-1.5 rounded-xl border border-indigo-400/20">
          <Users size={16} />
          <span className="text-sm font-medium">6인 단체</span>
        </div>
      </div>
    </div>
  );
};

export default Header;

import React from 'react';
import { Calendar, CreditCard, Info } from 'lucide-react';
import { TabType } from '../types';

interface NavigationProps {
  activeTab: TabType;
  setActiveTab: (tab: TabType) => void;
}

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab }) => {
  const tabs = [
    { id: 'itinerary', label: '일정표', icon: Calendar },
    { id: 'expenses', label: '정산', icon: CreditCard },
    { id: 'info', label: '여행정보', icon: Info },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-slate-200 px-6 py-4 flex justify-between items-center shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-20">
      {tabs.map((tab) => {
        const Icon = tab.icon;
        const isActive = activeTab === tab.id;
        return (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as TabType)}
            className={`flex flex-col items-center gap-1 transition-all ${
              isActive ? 'text-indigo-600 scale-110' : 'text-slate-400'
            }`}
          >
            <Icon size={24} strokeWidth={isActive ? 2.5 : 2} />
            <span className={`text-[11px] font-bold ${isActive ? 'opacity-100' : 'opacity-70'}`}>
              {tab.label}
            </span>
          </button>
        );
      })}
    </nav>
  );
};

export default Navigation;

import React, { useState } from 'react';
import { ChevronDown, ChevronUp, Plus, Trash2, Clock, Star, AlertCircle } from 'lucide-react';
import { DaySchedule, Activity } from '../types';

interface ItineraryTabProps {
  itinerary: DaySchedule[];
  onUpdate: (newItinerary: DaySchedule[]) => void;
}

const ItineraryTab: React.FC<ItineraryTabProps> = ({ itinerary, onUpdate }) => {
  const [openDay, setOpenDay] = useState<string | null>('day1');
  const [showAddModal, setShowAddModal] = useState<string | null>(null); // 'timeline' or 'resort'
  const [activeDayId, setActiveDayId] = useState<string | null>(null);

  const toggleDay = (id: string) => {
    setOpenDay(openDay === id ? null : id);
  };

  const removeActivity = (dayId: string, type: 'timeline' | 'resort', activityId: string) => {
    const updated = itinerary.map(day => {
      if (day.id === dayId) {
        return {
          ...day,
          [type === 'timeline' ? 'timeline' : 'resortProgram']: 
            (day[type === 'timeline' ? 'timeline' : 'resortProgram'] || []).filter(a => a.id !== activityId)
        };
      }
      return day;
    });
    onUpdate(updated);
  };

  const addActivity = (dayId: string, type: 'timeline' | 'resort', desc: string, time: string) => {
    const updated = itinerary.map(day => {
      if (day.id === dayId) {
        const newActivity: Activity = {
          id: Math.random().toString(36).substr(2, 9),
          time,
          description: desc
        };
        return {
          ...day,
          [type === 'timeline' ? 'timeline' : 'resortProgram']: 
            [...(day[type === 'timeline' ? 'timeline' : 'resortProgram'] || []), newActivity].sort((a,b) => a.time.localeCompare(b.time))
        };
      }
      return day;
    });
    onUpdate(updated);
    setShowAddModal(null);
  };

  return (
    <div className="p-4 space-y-4">
      {itinerary.map((day) => (
        <div key={day.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <button
            onClick={() => toggleDay(day.id)}
            className="w-full flex items-center justify-between p-4 hover:bg-slate-50 transition-colors"
          >
            <div className="flex items-center gap-4">
              <div className="bg-indigo-100 text-indigo-700 w-12 h-12 rounded-xl flex flex-col items-center justify-center font-bold">
                <span className="text-[10px] leading-tight opacity-70 uppercase">{day.dayName.substr(0, 3)}</span>
                <span className="text-base leading-tight">{day.date.split('(')[0]}</span>
              </div>
              <div className="text-left">
                <h3 className="font-bold text-slate-800">{day.title}</h3>
                <p className="text-xs text-slate-500">{day.timeline.length}개의 일정</p>
              </div>
            </div>
            {openDay === day.id ? <ChevronUp className="text-slate-400" /> : <ChevronDown className="text-slate-400" />}
          </button>

          {openDay === day.id && (
            <div className="px-4 pb-4 animate-fadeIn">
              {/* Resort Programs Section */}
              {day.resortProgram && day.resortProgram.length > 0 && (
                <div className="mb-6">
                  <div className="flex justify-between items-center mb-3">
                    <h4 className="text-xs font-bold text-indigo-600 uppercase tracking-wider flex items-center gap-1">
                      <Star size={12} fill="currentColor" /> 리조트 액티비티
                    </h4>
                    <button 
                      onClick={() => { setActiveDayId(day.id); setShowAddModal('resort'); }}
                      className="p-1 text-slate-400 hover:text-indigo-600"
                    >
                      <Plus size={16} />
                    </button>
                  </div>
                  <div className="space-y-2">
                    {day.resortProgram.map((item) => (
                      <div key={item.id} className="group flex items-start justify-between bg-indigo-50/50 p-2.5 rounded-lg border border-indigo-100/50">
                        <div className="flex items-start gap-3">
                          <span className="text-[10px] font-bold text-indigo-500 mt-1 whitespace-nowrap">{item.time}</span>
                          <div>
                            <p className="text-sm font-medium text-slate-700">
                              {item.description}
                              {item.isPaid && <span className="ml-1 text-orange-500" title="유료">💰</span>}
                              {item.requiresBooking && <span className="ml-1 text-red-500" title="예약필수">📌</span>}
                            </p>
                          </div>
                        </div>
                        <button onClick={() => removeActivity(day.id, 'resort', item.id)} className="opacity-0 group-hover:opacity-100 p-1 text-red-400 transition-opacity">
                          <Trash2 size={14} />
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Timeline Section */}
              <div>
                <div className="flex justify-between items-center mb-3">
                  <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center gap-1">
                    <Clock size={12} /> 메인 타임라인
                  </h4>
                  <button 
                    onClick={() => { setActiveDayId(day.id); setShowAddModal('timeline'); }}
                    className="p-1 text-slate-400 hover:text-indigo-600"
                  >
                    <Plus size={16} />
                  </button>
                </div>
                <div className="space-y-4 relative before:absolute before:left-[7px] before:top-2 before:bottom-2 before:w-[1px] before:bg-slate-200">
                  {day.timeline.map((item) => (
                    <div key={item.id} className="group relative pl-6">
                      <div className="absolute left-0 top-1.5 w-4 h-4 rounded-full bg-white border-2 border-indigo-400 z-10"></div>
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-bold text-slate-400 mb-0.5">{item.time}</p>
                          <p className="text-sm font-semibold text-slate-700 leading-snug">{item.description}</p>
                        </div>
                        <button onClick={() => removeActivity(day.id, 'timeline', item.id)} className="opacity-0 group-hover:opacity-100 p-1 text-red-400 transition-opacity">
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      ))}

      {/* Basic instructions */}
      <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100 flex gap-3 items-start">
        <AlertCircle size={20} className="text-amber-600 shrink-0 mt-0.5" />
        <div className="text-xs text-amber-800 space-y-1">
          <p className="font-bold">참고 안내</p>
          <p>• 💰 이모지는 예약 및 유료 프로그램입니다.</p>
          <p>• 📌 이모지는 예약 필수 프로그램입니다.</p>
          <p>• 일정을 길게 누르거나 마우스 오버 시 삭제 버튼이 나타납니다.</p>
        </div>
      </div>

      {/* Add Modal Placeholder (Simplified for single-file implementation) */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl w-full max-w-xs p-6 shadow-2xl animate-scaleIn">
            <h3 className="text-lg font-bold mb-4">{showAddModal === 'timeline' ? '메인 일정' : '리조트 프로그램'} 추가</h3>
            <form onSubmit={(e) => {
              e.preventDefault();
              const form = e.target as HTMLFormElement;
              const time = (form.elements.namedItem('time') as HTMLInputElement).value;
              const desc = (form.elements.namedItem('desc') as HTMLInputElement).value;
              if (activeDayId) addActivity(activeDayId, showAddModal as 'timeline' | 'resort', desc, time);
            }}>
              <div className="space-y-4">
                <div>
                  <label className="text-xs font-bold text-slate-500 mb-1 block">시간</label>
                  <input name="time" type="text" placeholder="예: 09:00" required className="w-full bg-slate-100 p-3 rounded-xl border-none text-sm" />
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-500 mb-1 block">내용</label>
                  <input name="desc" type="text" placeholder="활동 내용을 입력하세요" required className="w-full bg-slate-100 p-3 rounded-xl border-none text-sm" />
                </div>
              </div>
              <div className="flex gap-3 mt-6">
                <button type="button" onClick={() => setShowAddModal(null)} className="flex-1 py-3 text-slate-500 font-bold text-sm">취소</button>
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm">추가하기</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ItineraryTab;

import React, { useState, useMemo } from 'react';
import { Plus, Trash2, Banknote, CreditCard, ChevronDown, Check } from 'lucide-react';
import { Expense, Category, Currency, User } from '../types';
import { VND_TO_KRW_RATE, GROUP_SIZE } from '../constants';

interface ExpenseTabProps {
  expenses: Expense[];
  onUpdate: (newExpenses: Expense[]) => void;
  user: User;
}

const ExpenseTab: React.FC<ExpenseTabProps> = ({ expenses, onUpdate, user }) => {
  const [showForm, setShowForm] = useState(false);
  const [amount, setAmount] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState<Category>(Category.FOOD);
  const [currency, setCurrency] = useState<Currency>(Currency.VND);

  const stats = useMemo(() => {
    const totalKRW = expenses.reduce((acc, exp) => {
      const val = exp.currency === Currency.VND ? exp.amount * VND_TO_KRW_RATE : exp.amount;
      return acc + val;
    }, 0);

    return {
      total: totalKRW,
      perPerson: totalKRW / GROUP_SIZE
    };
  }, [expenses]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !description) return;

    const newExpense: Expense = {
      id: Math.random().toString(36).substr(2, 9),
      description,
      amount: parseFloat(amount.replace(/,/g, '')),
      currency,
      category,
      timestamp: Date.now(),
      createdBy: user.name
    };

    onUpdate([newExpense, ...expenses]);
    setShowForm(false);
    setAmount('');
    setDescription('');
  };

  const removeExpense = (id: string) => {
    onUpdate(expenses.filter(e => e.id !== id));
  };

  const formatMoney = (val: number, curr: Currency) => {
    if (curr === Currency.VND) {
      return val.toLocaleString() + ' đ';
    }
    return '₩ ' + Math.round(val).toLocaleString();
  };

  const categories = [
    { type: Category.FOOD, icon: '🍔', color: 'bg-orange-100 text-orange-600' },
    { type: Category.TRANSPORT, icon: '🚕', color: 'bg-blue-100 text-blue-600' },
    { type: Category.ACCOMMODATION, icon: '🏨', color: 'bg-purple-100 text-purple-600' },
    { type: Category.SHOPPING, icon: '🛍️', color: 'bg-pink-100 text-pink-600' },
    { type: Category.ALCOHOL, icon: '🍺', color: 'bg-red-100 text-red-600' },
    { type: Category.OTHER, icon: '✨', color: 'bg-slate-100 text-slate-600' },
  ];

  return (
    <div className="p-4 space-y-4">
      {/* Summary Card */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-slate-500 font-bold text-xs uppercase tracking-wider">전체 지출 요약</h3>
          <span className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded-full font-bold">인원 6명</span>
        </div>
        <div className="space-y-4">
          <div>
            <p className="text-slate-400 text-xs mb-1">총 지출액 (KRW)</p>
            <h2 className="text-3xl font-black text-slate-800">₩ {Math.round(stats.total).toLocaleString()}</h2>
          </div>
          <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
            <div>
              <p className="text-slate-400 text-[10px] mb-0.5">1인당 부담금</p>
              <p className="text-lg font-bold text-indigo-600">₩ {Math.round(stats.perPerson).toLocaleString()}</p>
            </div>
            <button 
              onClick={() => setShowForm(true)}
              className="bg-indigo-600 text-white p-4 rounded-2xl shadow-lg shadow-indigo-200 active:scale-95 transition-transform"
            >
              <Plus size={24} />
            </button>
          </div>
        </div>
      </div>

      {/* Expense List */}
      <div className="space-y-3">
        <h4 className="font-bold text-slate-700 px-1 text-sm">최근 내역</h4>
        {expenses.length === 0 ? (
          <div className="py-12 text-center bg-white rounded-3xl border border-dashed border-slate-300">
            <Banknote className="mx-auto text-slate-200 mb-2" size={40} />
            <p className="text-sm text-slate-400">등록된 지출 내역이 없습니다</p>
          </div>
        ) : (
          expenses.map((exp) => (
            <div key={exp.id} className="group bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
              <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shrink-0 ${
                categories.find(c => c.type === exp.category)?.color
              }`}>
                {categories.find(c => c.type === exp.category)?.icon}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex justify-between items-start">
                  <h5 className="font-bold text-slate-800 truncate pr-2">{exp.description}</h5>
                  <button 
                    onClick={() => removeExpense(exp.id)}
                    className="text-slate-300 hover:text-red-400 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
                <div className="flex justify-between items-end mt-1">
                  <div>
                    <span className="text-[10px] text-slate-400">{new Date(exp.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    <span className="mx-1 text-[10px] text-slate-200">|</span>
                    <span className="text-[10px] text-indigo-500 font-medium">{exp.createdBy}</span>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-slate-700 leading-none">{formatMoney(exp.amount, exp.currency)}</p>
                    {exp.currency === Currency.VND && (
                      <p className="text-[10px] text-slate-400 mt-1">≈ ₩ {Math.round(exp.amount * VND_TO_KRW_RATE).toLocaleString()}</p>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Add Form Drawer */}
      {showForm && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-end justify-center">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] p-8 animate-slideUp">
            <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-8"></div>
            <h3 className="text-xl font-bold text-slate-800 mb-6">새 지출 추가</h3>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="flex gap-2">
                {categories.map((cat) => (
                  <button
                    key={cat.type}
                    type="button"
                    onClick={() => setCategory(cat.type)}
                    className={`flex-1 aspect-square rounded-2xl flex flex-col items-center justify-center gap-1 transition-all border-2 ${
                      category === cat.type 
                        ? 'border-indigo-600 bg-indigo-50 text-indigo-600 scale-105' 
