import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TabType, Expense, User, DaySchedule } from './types';
import { INITIAL_ITINERARY, GROUP_SIZE, SYNC_INTERVAL, TRIP_ID } from './constants';
import Header from './components/Header';
import Navigation from './components/Navigation';
import ItineraryTab from './tabs/ItineraryTab';
import ExpenseTab from './tabs/ExpenseTab';
import InfoTab from './tabs/InfoTab';

// BroadcastChannel for local cross-tab sync
const syncChannel = new BroadcastChannel('trip_sync_channel');

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('itinerary');
  const [user, setUser] = useState<User | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [itinerary, setItinerary] = useState<DaySchedule[]>(INITIAL_ITINERARY);
  const [lastSynced, setLastSynced] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);

  // Load from localStorage and handle auto-login
  useEffect(() => {
    const savedExpenses = localStorage.getItem('trip_expenses');
    const savedItinerary = localStorage.getItem('trip_itinerary');
    const savedUser = localStorage.getItem('trip_user');

    if (savedExpenses) setExpenses(JSON.parse(savedExpenses));
    if (savedItinerary) setItinerary(JSON.parse(savedItinerary));

    if (savedUser) {
      setUser(JSON.parse(savedUser));
    } else {
      const anonymousUser = { id: 'anon-' + Math.random().toString(36).substr(2, 5), name: '익명' };
      setUser(anonymousUser);
      localStorage.setItem('trip_user', JSON.stringify(anonymousUser));
    }
  }, []);

  // REAL-TIME SYNC LOGIC (Polling Simulation)
  // In a real app, this would be a fetch to a database like Supabase or Firebase.
  useEffect(() => {
    const pollSync = async () => {
      setIsSyncing(true);

      // Simulate network request to fetch global state
      // We use a mock delay to represent network latency
      await new Promise(resolve => setTimeout(resolve, 800));

      // For this demo, we use a shared key in localStorage to simulate "cloud" 
      // so User A and User B on the SAME browser can see updates.
      // To make it cross-device, replace this with a real fetch() call.
      const cloudData = localStorage.getItem(`cloud_sync_${TRIP_ID}`);
      if (cloudData) {
        const { remoteExpenses, remoteItinerary } = JSON.parse(cloudData);

        // Simple merge: remote wins if newer (using timestamps or length for demo)
        if (remoteExpenses.length !== expenses.length) {
          setExpenses(remoteExpenses);
          localStorage.setItem('trip_expenses', JSON.stringify(remoteExpenses));
        }
        if (JSON.stringify(remoteItinerary) !== JSON.stringify(itinerary)) {
          setItinerary(remoteItinerary);
          localStorage.setItem('trip_itinerary', JSON.stringify(remoteItinerary));
        }
      }

      setLastSynced(new Date());
      setIsSyncing(false);
    };

    const interval = setInterval(pollSync, SYNC_INTERVAL);
    return () => clearInterval(interval);
  }, [expenses.length, itinerary]);

  // Sync listener for local tabs
  useEffect(() => {
    const handleSync = (event: MessageEvent) => {
      if (event.data.type === 'SYNC_ALL') {
        const { expenses: remoteExpenses, itinerary: remoteItinerary } = event.data.payload;
        setExpenses(remoteExpenses);
        setItinerary(remoteItinerary);
      }
    };
    syncChannel.addEventListener('message', handleSync);
    return () => syncChannel.removeEventListener('message', handleSync);
  }, []);

  const pushToCloud = useCallback((newExpenses: Expense[], newItinerary: DaySchedule[]) => {
    // 1. Update local storage
    localStorage.setItem('trip_expenses', JSON.stringify(newExpenses));
    localStorage.setItem('trip_itinerary', JSON.stringify(newItinerary));

    // 2. Update local cross-tab
    syncChannel.postMessage({ 
      type: 'SYNC_ALL', 
      payload: { expenses: newExpenses, itinerary: newItinerary } 
    });

    // 3. Update "Cloud" (Shared localStorage key for demo)
    localStorage.setItem(`cloud_sync_${TRIP_ID}`, JSON.stringify({
      remoteExpenses: newExpenses,
      remoteItinerary: newItinerary,
      updatedAt: Date.now()
    }));
  }, []);

  const saveExpenses = useCallback((newExpenses: Expense[]) => {
    setExpenses(newExpenses);
    pushToCloud(newExpenses, itinerary);
  }, [itinerary, pushToCloud]);

  const saveItinerary = useCallback((newItinerary: DaySchedule[]) => {
    setItinerary(newItinerary);
    pushToCloud(expenses, newItinerary);
  }, [expenses, pushToCloud]);

  const handleLogout = () => {
    localStorage.removeItem('trip_user');
    window.location.reload();
  };

  if (!user) {
    return <div className="min-h-screen bg-slate-50 flex items-center justify-center">
      <div className="animate-pulse text-indigo-600 font-bold">연결 중...</div>
    </div>;
  }

  return (
    <div className="flex flex-col min-h-screen bg-slate-50 max-w-md mx-auto relative shadow-xl overflow-hidden">
      <Header 
        onLogout={handleLogout} 
        isSyncing={isSyncing} 
        lastSynced={lastSynced}
      />

      <main className="flex-1 overflow-y-auto pb-24 no-scrollbar">
        {activeTab === 'itinerary' && (
          <ItineraryTab 
            itinerary={itinerary} 
            onUpdate={saveItinerary} 
          />
        )}
        {activeTab === 'expenses' && (
          <ExpenseTab 
            expenses={expenses} 
            onUpdate={saveExpenses} 
            user={user}
          />
        )}
        {activeTab === 'info' && (
          <InfoTab />
        )}
      </main>

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
    </div>
  );
};

export default App;

