    const teams = [];
    for (let i = 0; i < shuffled.length; i += size) {
      teams.push(shuffled.slice(i, i + size));
    }
    setGameResult({ type: 'team', data: teams });
  };

  const handlePickN = () => {
    const shuffled = shuffle(PAYERS);
    setGameResult({ type: 'pick', data: shuffled.slice(0, pickCount) });
  };

  const handleAddIdea = (e: React.FormEvent) => {
    e.preventDefault();
