import React, { useState, useMemo } from 'react';
import { Package, User, CheckCircle2, Circle, Plus, Trash2, ShieldCheck, UserCheck, Filter, RotateCcw, Users } from 'lucide-react';
import { PrepItem, User as UserType } from '../types';
import { PAYERS, RECOMMENDED_PREP_ITEMS } from '../constants';

interface PrepTabProps {
  prepItems: PrepItem[];
  onUpdate: (items: PrepItem[]) => void;
  user: UserType;
}

const PrepTab: React.FC<PrepTabProps> = ({ prepItems, onUpdate, user }) => {
  const [activeFilter, setActiveFilter] = useState<string>('전체');
  const [newItemText, setNewItemText] = useState('');
  const [isCommonMode, setIsCommonMode] = useState(false);
  const [selectedAssignees, setSelectedAssignees] = useState<string[]>([]);

  const filteredItems = useMemo(() => {
    if (activeFilter === '전체') return prepItems;
    return prepItems.filter(item => {
      if (item.isCommon) {
        // 다중 담당자 중 한 명이라도 필터링된 이름과 일치하면 표시
        return item.assignedTo?.includes(activeFilter);
      } else {
        return item.createdBy === activeFilter;
      }
    });
  }, [prepItems, activeFilter]);

  const commonItems = useMemo(() => prepItems.filter(i => i.isCommon), [prepItems]);

  const toggleComplete = (id: string) => {
    onUpdate(prepItems.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const toggleAssignee = (name: string) => {
    setSelectedAssignees(prev => {
      if (prev.includes(name)) {
        return prev.filter(n => n !== name);
      }
      if (prev.length >= 5) {
        alert("담당자는 최대 5명까지 선택 가능합니다.");
        return prev;
      }
      return [...prev, name];
    });
  };

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemText.trim()) return;

    const newItem: PrepItem = {
      id: Math.random().toString(36).substr(2, 9),
      text: newItemText.trim(),
      isCommon: isCommonMode,
      assignedTo: isCommonMode && selectedAssignees.length > 0 ? selectedAssignees : undefined,
      isCompleted: false,
      createdBy: user.name
    };

    onUpdate([...prepItems, newItem]);
    setNewItemText('');
    setSelectedAssignees([]);
  };

  const removeItem = (id: string) => {
    onUpdate(prepItems.filter(i => i.id !== id));
  };

  const resetToRecommended = () => {
    if (confirm('현재 리스트를 지우고 이미지의 추천 리스트로 초기화할까요?')) {
      // RECOMMENDED_PREP_ITEMS는 string[]로 마이그레이션이 필요할 수 있으나 
      // 현재 UI 로직에서 안전하게 처리됨
      onUpdate(RECOMMENDED_PREP_ITEMS.map(item => ({...item, assignedTo: undefined})));
    }
  };

  return (
    <div className="p-4 space-y-6 pb-20">
      {/* Name Filter Bar */}
      <section className="space-y-3">
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-2">
            <Filter size={16} className="text-slate-400" />
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest">담당자별 보기</h3>
          </div>
          <button 
            onClick={resetToRecommended}
            className="text-[10px] font-bold text-indigo-500 flex items-center gap-1 bg-indigo-50 px-2 py-1 rounded-md"
          >
            <RotateCcw size={10} /> 추천리스트 복구
          </button>
        </div>
        <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
          <button
            onClick={() => setActiveFilter('전체')}
            className={`px-4 py-2 rounded-xl text-xs font-black transition-all border shrink-0 ${
              activeFilter === '전체' ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500'
            }`}
          >
            전체 리스트
          </button>
          {PAYERS.map(name => (
            <button
              key={name}
              onClick={() => setActiveFilter(name)}
              className={`px-4 py-2 rounded-xl text-xs font-black transition-all border shrink-0 flex items-center gap-1.5 ${
                activeFilter === name ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500'
              }`}
            >
              <User size={12} />
              {name}
            </button>
          ))}
        </div>
      </section>

      {/* Add New Item Form */}
      <section className="bg-white rounded-[2rem] border border-slate-200 p-5 shadow-sm space-y-4">
        <div className="flex items-center gap-2">
          <Plus size={18} className="text-indigo-600" />
          <h3 className="font-bold text-slate-800 text-sm">항목 추가</h3>
        </div>

        <form onSubmit={addItem} className="space-y-4">
          <input
            type="text"
            value={newItemText}
            onChange={(e) => setNewItemText(e.target.value)}
            placeholder="예: 멀티탭 3개, 샤워 필터 등"
            className="w-full bg-slate-50 border-none rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-100 font-medium"
          />

          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <label className="text-[11px] font-black text-slate-400 uppercase">분류 선택</label>
              <button
                type="button"
                onClick={() => setIsCommonMode(!isCommonMode)}
                className={`px-4 py-1.5 rounded-lg text-[10px] font-black transition-all border flex items-center gap-2 ${
                  isCommonMode ? 'bg-emerald-500 border-emerald-500 text-white shadow-md' : 'bg-slate-50 border-slate-200 text-slate-400'
                }`}
              >
                {isCommonMode ? <ShieldCheck size={12} /> : <User size={12} />}
                {isCommonMode ? '공용 물품' : '개인 물품'}
              </button>
            </div>

            {isCommonMode && (
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-3 animate-fadeIn">
                <div className="flex justify-between items-center">
                  <span className="text-[11px] font-black text-slate-500">담당자 지정 (최대 5명)</span>
                  <span className="text-[10px] font-bold text-indigo-500">{selectedAssignees.length}/5 선택됨</span>
                </div>
                <div className="flex flex-wrap gap-2">
                  {PAYERS.map(name => {
                    const isSelected = selectedAssignees.includes(name);
                    return (
                      <button
                        key={name}
                        type="button"
                        onClick={() => toggleAssignee(name)}
                        className={`px-3 py-2 rounded-xl text-[10px] font-bold border transition-all ${
                          isSelected 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' 
                          : 'bg-white border-slate-200 text-slate-400'
                        }`}
                      >
                        {name}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg shadow-indigo-100 active:scale-95 transition-all"
          >
            준비물 리스트에 추가
          </button>
        </form>
      </section>

      {/* Preparation List */}
      <section className="space-y-6">
        {activeFilter === '전체' && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 px-1">
              <ShieldCheck size={18} className="text-emerald-500" />
              <h3 className="font-bold text-slate-800">공동 준비물 <span className="text-slate-400 text-xs ml-1">({commonItems.length})</span></h3>
            </div>
            <div className="space-y-2">
              {commonItems.map(item => (
                <PrepListItem key={item.id} item={item} onToggle={toggleComplete} onRemove={removeItem} />
              ))}
              {commonItems.length === 0 && <p className="text-center py-8 text-xs text-slate-300 font-medium bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">등록된 공용 물품이 없습니다.</p>}
            </div>
          </div>
        )}

        <div className="space-y-3">
          <div className="flex items-center gap-2 px-1">
            <UserCheck size={18} className={`${activeFilter === '전체' ? 'text-indigo-500' : 'text-emerald-500'}`} />
            <h3 className="font-bold text-slate-800">
              {activeFilter === '전체' ? '개인별 체크리스트' : `${activeFilter}님의 준비물`}
              <span className="text-slate-400 text-xs ml-1">({filteredItems.filter(i => activeFilter === '전체' ? !i.isCommon : true).length})</span>
            </h3>
          </div>
          <div className="space-y-2">
            {filteredItems
              .filter(item => activeFilter === '전체' ? !item.isCommon : true)
              .map(item => (
                <PrepListItem key={item.id} item={item} onToggle={toggleComplete} onRemove={removeItem} />
              ))
            }
            {filteredItems.length === 0 && <p className="text-center py-8 text-xs text-slate-300 font-medium bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">준비할 물품이 없습니다.</p>}
          </div>
        </div>
      </section>

      <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100 flex gap-3">
        <Users size={20} className="text-amber-500 shrink-0" />
        <p className="text-[10px] text-amber-800 font-bold leading-relaxed">
          멀티탭이나 비상의약품처럼 여러 명이 각자 챙겨야 할 물품은 '공용 물품'으로 설정하고 담당자를 다수 지정해보세요! 본인 이름을 선택하면 챙겨야 할 목록을 모아볼 수 있습니다.
        </p>
      </div>
    </div>
  );
};

interface PrepListItemProps {
  item: PrepItem;
  onToggle: (id: string) => void;
  onRemove: (id: string) => void;
}

const PrepListItem: React.FC<PrepListItemProps> = ({ item, onToggle, onRemove }) => {
  return (
    <div 
      className={`p-4 bg-white rounded-2xl border transition-all flex items-center gap-3 group shadow-sm ${
        item.isCompleted ? 'border-slate-100 bg-slate-50/30 opacity-60' : 'border-slate-200'
      }`}
    >
      <button 
        onClick={() => onToggle(item.id)}
        className={`shrink-0 transition-colors ${item.isCompleted ? 'text-indigo-500' : 'text-slate-300'}`}
      >
        {item.isCompleted ? <CheckCircle2 size={24} fill="currentColor" className="text-indigo-500 text-white" /> : <Circle size={24} />}
      </button>

      <div className="flex-1 min-w-0" onClick={() => onToggle(item.id)}>
        <p className={`text-sm font-semibold truncate ${item.isCompleted ? 'line-through text-slate-400' : 'text-slate-700'}`}>
          {item.text}
        </p>
        <div className="flex flex-wrap gap-1 items-center mt-1">
          {item.isCommon && (
            <span className="bg-emerald-50 text-emerald-600 text-[9px] font-black px-1.5 py-0.5 rounded-md flex items-center gap-1">
              <ShieldCheck size={8} /> 공용
            </span>
          )}
          {item.assignedTo && item.assignedTo.length > 0 && item.assignedTo.map(name => (
            <span key={name} className="bg-indigo-50 text-indigo-500 text-[9px] font-black px-1.5 py-0.5 rounded-md flex items-center gap-1">
              <User size={8} /> {name}
            </span>
          ))}
          {!item.isCommon && (
            <span className="bg-slate-50 text-slate-400 text-[9px] font-black px-1.5 py-0.5 rounded-md">
              {item.createdBy} 등록
            </span>
          )}
        </div>
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); onRemove(item.id); }}
        className="text-slate-200 hover:text-rose-400 p-2 transition-colors opacity-100 sm:opacity-0 group-hover:opacity-100"
      >
        <Trash2 size={16} />
      </button>
    </div>
  );
};

