import React, { useState, useMemo } from 'react';
import { Package, User, CheckCircle2, Circle, Plus, Trash2, ShieldCheck, UserCheck, Filter, RotateCcw, Users, LayoutList, Star } from 'lucide-react';
import { PrepItem, User as UserType } from '../types';
import { PAYERS, RECOMMENDED_PREP_ITEMS } from '../constants';

interface PrepTabProps {
  prepItems: PrepItem[];
  onUpdate: (items: PrepItem[]) => void;
  user: UserType;
}

const PrepTab: React.FC<PrepTabProps> = ({ prepItems, onUpdate, user }) => {
  const [activeFilter, setActiveFilter] = useState<string>('전체');
  const [newItemText, setNewItemText] = useState('');
  const [isCommonMode, setIsCommonMode] = useState(false);
  const [selectedAssignees, setSelectedAssignees] = useState<string[]>([]);

  const filteredItems = useMemo(() => {
    if (activeFilter === '전체') return prepItems;
    return prepItems.filter(item => {
      if (item.isCommon) {
        // 공용 물품: 담당자로 지정된 경우 노출
        return item.assignedTo?.includes(activeFilter);
      } else {
        // 개인 물품: 본인이 만든 것이거나, '시스템'이 만든 필수 품목(여권 등)은 모두에게 노출
        return item.createdBy === activeFilter || item.createdBy === '시스템';
      }
    });
  }, [prepItems, activeFilter]);

  const commonItems = useMemo(() => prepItems.filter(i => i.isCommon), [prepItems]);

  const toggleComplete = (id: string) => {
    onUpdate(prepItems.map(item => 
      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const toggleAssignee = (name: string) => {
    setSelectedAssignees(prev => {
      if (prev.includes(name)) {
        return prev.filter(n => n !== name);
      }
      if (prev.length >= 5) {
        alert("담당자는 최대 5명까지 선택 가능합니다.");
        return prev;
      }
      return [...prev, name];
    });
  };

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemText.trim()) return;

    const newItem: PrepItem = {
      id: Math.random().toString(36).substr(2, 9),
      text: newItemText.trim(),
      isCommon: isCommonMode,
      assignedTo: isCommonMode && selectedAssignees.length > 0 ? selectedAssignees : undefined,
      isCompleted: false,
      createdBy: user.name
    };

    onUpdate([...prepItems, newItem]);
    setNewItemText('');
    setSelectedAssignees([]);
  };

  const removeItem = (id: string) => {
    onUpdate(prepItems.filter(i => i.id !== id));
  };

  const resetToRecommended = () => {
    if (confirm('현재 리스트를 지우고 이미지의 추천 리스트로 초기화할까요?')) {
      onUpdate(RECOMMENDED_PREP_ITEMS);
    }
  };

  return (
    <div className="p-4 space-y-6 pb-20">
      {/* 2-Row Grid Filter Bar - Optimized for single view */}
      <section className="space-y-3">
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-2">
            <Filter size={14} className="text-slate-400" />
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">담당자별 보기</h3>
          </div>
          <button 
            onClick={resetToRecommended}
            className="text-[9px] font-bold text-indigo-400 flex items-center gap-1 bg-indigo-50/50 px-2 py-1 rounded-lg"
          >
            <RotateCcw size={10} /> 추천리스트 복구
          </button>
        </div>

        <div className="grid grid-cols-4 gap-2">
          <button
            onClick={() => setActiveFilter('전체')}
            className={`py-2.5 rounded-xl text-[11px] font-black transition-all border flex items-center justify-center gap-1 ${
              activeFilter === '전체' ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500'
            }`}
          >
            <LayoutList size={12} />
            전체
          </button>
          {PAYERS.map(name => (
            <button
              key={name}
              onClick={() => setActiveFilter(name)}
              className={`py-2.5 rounded-xl text-[11px] font-black transition-all border flex items-center justify-center gap-1 ${
                activeFilter === name ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500'
              }`}
            >
              <User size={12} />
              {name}
            </button>
          ))}
        </div>
      </section>

      {/* Personalized Header */}
      {activeFilter !== '전체' && (
        <div className="bg-indigo-600 text-white p-5 rounded-[2rem] shadow-lg shadow-indigo-100 flex items-center justify-between animate-fadeIn">
          <div>
            <h4 className="text-xs font-bold opacity-80 mb-1">{activeFilter}님의 맞춤 리스트</h4>
            <p className="text-lg font-black tracking-tight">필수 + 개인 {filteredItems.length}개</p>
          </div>
          <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center">
            <Package size={24} />
          </div>
        </div>
      )}

      {/* Add New Item Form */}
      <section className="bg-white rounded-[2rem] border border-slate-200 p-5 shadow-sm space-y-4">
        <div className="flex items-center gap-2">
          <Plus size={18} className="text-indigo-600" />
          <h3 className="font-bold text-slate-800 text-sm">리스트 추가</h3>
        </div>

        <form onSubmit={addItem} className="space-y-4">
          <input
            type="text"
            value={newItemText}
            onChange={(e) => setNewItemText(e.target.value)}
            placeholder="예: 컵라면 5개, 잠옷 등"
            className="w-full bg-slate-50 border-none rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-100 font-medium placeholder:text-slate-300"
          />

          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">분류</label>
              <button
                type="button"
                onClick={() => setIsCommonMode(!isCommonMode)}
                className={`px-4 py-1.5 rounded-xl text-[10px] font-black transition-all border flex items-center gap-2 ${
                  isCommonMode ? 'bg-emerald-500 border-emerald-500 text-white shadow-md' : 'bg-slate-50 border-slate-200 text-slate-400'
                }`}
              >
                {isCommonMode ? <ShieldCheck size={12} /> : <User size={12} />}
                {isCommonMode ? '공용 물품' : '개인 물품'}
              </button>
            </div>

            {isCommonMode && (
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-3 animate-fadeIn">
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-tighter">담당자 지정 (최대 5명)</span>
                  <span className="text-[9px] font-bold text-indigo-500 px-2 py-0.5 bg-white rounded-md border border-indigo-100">{selectedAssignees.length}/5</span>
                </div>
                <div className="grid grid-cols-3 gap-1.5">
                  {PAYERS.map(name => {
                    const isSelected = selectedAssignees.includes(name);
                    return (
                      <button
                        key={name}
                        type="button"
                        onClick={() => toggleAssignee(name)}
                        className={`py-2 rounded-lg text-[10px] font-bold border transition-all ${
                          isSelected 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' 
                          : 'bg-white border-slate-200 text-slate-400'
                        }`}
                      >
                        {name}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-sm shadow-xl shadow-indigo-100 active:scale-95 transition-all"
          >
            추가하기
          </button>
        </form>
      </section>

      {/* Preparation List */}
      <section className="space-y-6">
        {/* Common View - Specific to filtered person or all */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 px-1">
            <Star size={18} className="text-amber-500" />
            <h3 className="font-bold text-slate-800">
              {activeFilter === '전체' ? '공통 필수 & 담당 품목' : `${activeFilter}님의 체크리스트`}
            </h3>
          </div>
          <div className="space-y-2">
            {filteredItems.map(item => (
              <PrepListItem 
                key={item.id} 
                item={item} 
                onToggle={toggleComplete} 
                onRemove={removeItem} 
                isSystem={item.createdBy === '시스템'}
              />
            ))}
            {filteredItems.length === 0 && <p className="text-center py-8 text-xs text-slate-300 font-medium bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">리스트가 비어있습니다.</p>}
          </div>
        </div>

        {/* Global Personal View - Only in 'All' view to manage everything */}
        {activeFilter === '전체' && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 px-1 border-t border-slate-100 pt-6">
              <UserCheck size={18} className="text-slate-400" />
              <h3 className="font-bold text-slate-400">전체 데이터 관리 <span className="text-[10px] font-medium">(시스템 필수 제외)</span></h3>
            </div>
            <div className="space-y-2">
              {prepItems
                .filter(i => i.createdBy !== '시스템')
                .map(item => (
                  <PrepListItem key={item.id} item={item} onToggle={toggleComplete} onRemove={removeItem} />
                ))
              }
            </div>
          </div>
        )}
      </section>

      <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100 flex gap-3">
        <Users size={20} className="text-amber-500 shrink-0" />
        <p className="text-[10px] text-amber-800 font-bold leading-relaxed">
          여권, 항공권 등 '공통 필수' 품목은 모든 멤버의 페이지에 기본으로 표시됩니다. 각자 본인의 짐을 챙기면서 하나씩 체크해보세요!
        </p>
      </div>
    </div>
  );
};

