      item.id === id ? { ...item, isCompleted: !item.isCompleted } : item
    ));
  };

  const toggleAssignee = (name: string) => {
    setSelectedAssignees(prev => {
      if (prev.includes(name)) return prev.filter(n => n !== name);
      if (prev.length >= 6) return prev;
      return [...prev, name];
    });
  };

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemText.trim()) return;

    const newItem: PrepItem = {
      id: Math.random().toString(36).substr(2, 9),
      text: newItemText.trim(),
      isCommon: isCommonMode,
      isCompleted: false,
      createdBy: user.name
    };

    // 공용/개인 상관없이 선택된 담당자가 있으면 추가
    if (selectedAssignees.length > 0) {
      newItem.assignedTo = selectedAssignees;
    } else if (!isCommonMode) {
      // 개인 물품인데 아무도 선택 안했으면 '나'를 담당자로 기본 지정
      newItem.assignedTo = [user.name];
    }

    onUpdate([...prepItems, newItem]);
    setNewItemText('');
    setSelectedAssignees([]);
  };

  const removeItem = (id: string) => {
    onUpdate(prepItems.filter(i => i.id !== id));
  };

  const resetToRecommended = () => {
    if (confirm('모든 데이터를 삭제하고 기본 리스트로 초기화할까요?')) {
      onUpdate(RECOMMENDED_PREP_ITEMS);
    }
  };

  return (
    <div className="p-4 space-y-6 pb-20 bg-slate-50/50 min-h-full">
      {/* View Filter Grid */}
      <section className="space-y-2">
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-1.5 opacity-40">
            <Filter size={12} />
            <span className="text-[10px] font-bold uppercase tracking-widest">View Member</span>
          </div>
          <button onClick={resetToRecommended} className="text-[10px] text-slate-400 font-medium flex items-center gap-1">
            <RotateCcw size={10} /> 초기화
          </button>
        </div>

        <div className="grid grid-cols-4 gap-1.5">
          <button
            onClick={() => setActiveFilter('전체')}
            className={`py-2 rounded-lg text-[11px] font-bold transition-all border ${
              activeFilter === '전체' ? 'bg-slate-800 border-slate-800 text-white shadow-sm' : 'bg-white border-slate-200 text-slate-500'
            }`}
          >
            전체리스트
          </button>
          {PAYERS.map(name => (
            <button
              key={name}
              onClick={() => setActiveFilter(name)}
              className={`py-2 rounded-lg text-[11px] font-bold transition-all border ${
                activeFilter === name ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' : 'bg-white border-slate-200 text-slate-500'
              }`}
            >
              {name}
            </button>
          ))}
        </div>
      </section>

      {/* Slim Add Form */}
      <section className="bg-white rounded-2xl border border-slate-200 p-4 space-y-4 shadow-sm">
        <div className="flex gap-2">
          <input
            type="text"
            value={newItemText}
            onChange={(e) => setNewItemText(e.target.value)}
            placeholder="품목 추가 (예: 컵라면)"
            className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-2.5 text-xs focus:ring-1 focus:ring-slate-200 font-medium"
          />
          <button
            onClick={addItem}
            className="bg-slate-800 text-white px-5 py-2.5 rounded-xl text-xs font-bold shrink-0 active:scale-95 transition-transform"
          >
            추가
          </button>
        </div>

        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <div className="flex gap-1.5">
              <button
                onClick={() => setIsCommonMode(true)}
                className={`px-3.5 py-2 rounded-lg text-[10px] font-bold border transition-all ${
                  isCommonMode ? 'bg-indigo-50 border-indigo-200 text-indigo-600 shadow-sm' : 'bg-white border-slate-100 text-slate-300'
                }`}
              >
                공용 물품
              </button>
              <button
                onClick={() => setIsCommonMode(false)}
                className={`px-3.5 py-2 rounded-lg text-[10px] font-bold border transition-all ${
                  !isCommonMode ? 'bg-blue-50 border-blue-200 text-blue-600 shadow-sm' : 'bg-white border-slate-100 text-slate-300'
                }`}
              >
                개인 물품
              </button>
            </div>
            <span className="text-[10px] text-slate-400 font-bold">담당자 선택</span>
          </div>

          <div className="grid grid-cols-6 gap-1 animate-fadeIn">
            {PAYERS.map(name => {
              const isSelected = selectedAssignees.includes(name);
              return (
                <button
                  key={name}
                  onClick={() => toggleAssignee(name)}
                  className={`py-2 rounded-md text-[10px] font-bold border transition-all ${
                    isSelected ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' : 'bg-slate-50 border-slate-100 text-slate-400'
                  }`}
                >
                  {name}
                </button>
              );
            })}
          </div>
        </div>
      </section>

      {/* Checklist Rendering */}
      <div className="space-y-6">
        {activeFilter === '전체' ? (
          <>
            <div className="space-y-2">
              <h3 className="text-[11px] font-black text-slate-400 px-1 uppercase tracking-wider flex items-center gap-2">
                <LayoutList size={12} /> 공용물품 리스트
              </h3>
              <div className="space-y-0.5 rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
                {prepItems.filter(i => i.isCommon).map(item => (
                  <MinimalListItem key={item.id} item={item} onToggle={toggleComplete} onRemove={removeItem} />
                ))}
              </div>
            </div>

            <div className="space-y-2">
              <h3 className="text-[11px] font-black text-slate-400 px-1 uppercase tracking-wider flex items-center gap-2">
                <User size={12} /> 개인물품 리스트
              </h3>
              <div className="space-y-0.5 rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
                {prepItems.filter(i => !i.isCommon).map(item => (
                  <MinimalListItem key={item.id} item={item} onToggle={toggleComplete} onRemove={removeItem} />
                ))}
              </div>
            </div>
          </>
        ) : (
          <div className="space-y-3">
            <h3 className="text-[11px] font-black text-indigo-500 px-1 uppercase tracking-wider flex items-center gap-2">
              <User size={12} /> {activeFilter}님의 체크리스트
            </h3>
            <div className="space-y-0.5 rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
              {filteredItems.map(item => (
                <MinimalListItem key={item.id} item={item} onToggle={toggleComplete} onRemove={removeItem} />
              ))}
              {filteredItems.length === 0 && (
                <div className="text-center py-12 bg-white">
                  <p className="text-[11px] text-slate-300 font-bold">체크할 항목이 없습니다.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

interface MinimalListItemProps {
  item: PrepItem;
  onToggle: (id: string) => void;
  onRemove: (id: string) => void;
}

const MinimalListItem: React.FC<MinimalListItemProps> = ({ item, onToggle, onRemove }) => {
  return (
    <div 
      className={`group flex items-center gap-3 py-3 px-4 transition-all ${
        item.isCommon 
          ? 'bg-indigo-50/40 hover:bg-indigo-50/60' 
          : 'bg-white hover:bg-slate-50'
      } ${item.isCompleted ? 'opacity-40 grayscale-[0.5]' : ''}`}
    >
      <button 
        onClick={() => onToggle(item.id)}
        className={`shrink-0 transition-colors ${item.isCompleted ? 'text-indigo-500' : 'text-slate-200 hover:text-slate-300'}`}
      >
        {item.isCompleted ? <CheckCircle2 size={20} fill="currentColor" className="text-white" /> : <Circle size={20} />}
      </button>

      <div className="flex-1 min-w-0 flex items-center justify-between gap-2" onClick={() => onToggle(item.id)}>
        <p className={`text-[13px] font-medium leading-tight truncate ${item.isCompleted ? 'line-through text-slate-400' : 'text-slate-700'}`}>
          {item.text}
        </p>

        <div className="flex flex-wrap gap-1 shrink-0 justify-end">
          {item.assignedTo && item.assignedTo.map(name => (
            <span key={name} className="text-[9px] font-black text-indigo-500/80 bg-white/80 border border-indigo-100 px-1.5 py-0.5 rounded shadow-sm">
              {name}
            </span>
          ))}
          {/* 생성자 표시는 제거함 (사용자 요청) */}
          {!item.isCommon && item.createdBy === '시스템' && (
            <span className="text-[9px] font-black text-blue-400/80 bg-blue-50/80 border border-blue-100 px-1.5 py-0.5 rounded">
              필수
            </span>
          )}
        </div>
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); onRemove(item.id); }}
        className="p-1.5 text-slate-200 hover:text-rose-400 hover:bg-rose-50 rounded-lg transition-all sm:opacity-0 group-hover:opacity-100 ml-1"
      >
        <Trash2 size={14} />
      </button>
    </div>
  );
};

export default PrepTab;

import React, { useState, useMemo } from 'react';
import { Plus, Trash2, Banknote, CreditCard, ChevronDown, Check, Calendar, User as UserIcon, Download, Share2, CloudUpload, CloudCheck } from 'lucide-react';
import { Expense, Category, Currency, User } from '../types';
import { VND_TO_KRW_RATE, GROUP_SIZE, EXPENSE_DATES, PAYERS } from '../constants';

interface ExpenseTabProps {
  expenses: Expense[];
  onUpdate: (newExpenses: Expense[]) => void;
  user: User;
}

const ExpenseTab: React.FC<ExpenseTabProps> = ({ expenses, onUpdate, user }) => {
  const [showForm, setShowForm] = useState(false);
  const [amount, setAmount] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState<Category>(Category.FOOD);
  const [currency, setCurrency] = useState<Currency>(Currency.VND);
  const [selectedDate, setSelectedDate] = useState<string | undefined>();
  const [selectedPayer, setSelectedPayer] = useState<string | undefined>();

  const stats = useMemo(() => {
    const totalKRW = expenses.reduce((acc, exp) => {
      const val = exp.currency === Currency.VND ? exp.amount * VND_TO_KRW_RATE : exp.amount;
      return acc + val;
    }, 0);

    return {
      total: totalKRW,
      perPerson: totalKRW / GROUP_SIZE
    };
  }, [expenses]);

  const exportToCSV = () => {
    if (expenses.length === 0) {
      alert("내보낼 지출 내역이 없습니다.");
      return;
    }

    const headers = ["날짜", "분류", "내용", "금액", "통화", "KRW 환산", "지출인", "등록자"];
    const rows = expenses.map(exp => {
      const krwValue = exp.currency === Currency.VND ? Math.round(exp.amount * VND_TO_KRW_RATE) : exp.amount;
      return [
        exp.expenseDate || '-',
        exp.category,
        exp.description,
        exp.amount,
        exp.currency,
        krwValue,
        exp.payer || '-',
        exp.createdBy
      ].join(",");
    });

    const csvContent = "\uFEFF" + [headers.join(","), ...rows].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `나트랑_정산내역_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !description) return;

    // Firebase는 undefined 값을 저장할 수 없으므로, 값이 있을 때만 필드를 추가합니다.
    const newExpense: any = {
      id: Math.random().toString(36).substr(2, 9),
      description,
      amount: parseFloat(amount.replace(/,/g, '')),
      currency,
      category,
      timestamp: Date.now(),
      createdBy: user.name
    };

    if (selectedDate) newExpense.expenseDate = selectedDate;
    if (selectedPayer) newExpense.payer = selectedPayer;

    onUpdate([newExpense as Expense, ...expenses]);

    setShowForm(false);
    setAmount('');
    setDescription('');
    setSelectedDate(undefined);
    setSelectedPayer(undefined);
  };

  const removeExpense = (id: string) => {
    if(confirm("이 지출 내역을 삭제할까요?")) {
      onUpdate(expenses.filter(e => e.id !== id));
    }
  };

  const formatMoney = (val: number, curr: Currency) => {
    if (curr === Currency.VND) {
      return val.toLocaleString() + ' đ';
    }
    return '₩ ' + Math.round(val).toLocaleString();
  };

  const categories = [
    { type: Category.FOOD, icon: '🍔', color: 'bg-orange-100 text-orange-600' },
    { type: Category.TRANSPORT, icon: '🚕', color: 'bg-blue-100 text-blue-600' },
    { type: Category.SHOPPING, icon: '🛍️', color: 'bg-pink-100 text-pink-600' },
    { type: Category.ALCOHOL, icon: '🍺', color: 'bg-red-100 text-red-600' },
    { type: Category.OTHER, icon: '✨', color: 'bg-slate-100 text-slate-600' },
    { type: Category.ACCOMMODATION, icon: '🏨', color: 'bg-purple-100 text-purple-600' },
  ];

  return (
    <div className="p-4 space-y-4">
      {/* Summary Card */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-slate-500 font-bold text-xs uppercase tracking-wider">전체 지출 요약</h3>
          <span className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded-full font-bold">인원 {GROUP_SIZE}명</span>
        </div>
        <div className="space-y-4">
          <div>
            <p className="text-slate-400 text-xs mb-1">총 지출액 (KRW)</p>
            <h2 className="text-3xl font-black text-slate-800">₩ {Math.round(stats.total).toLocaleString()}</h2>
          </div>
          <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
            <div>
              <p className="text-slate-400 text-[10px] mb-0.5">1인당 부담금</p>
              <p className="text-lg font-bold text-indigo-600">₩ {Math.round(stats.perPerson).toLocaleString()}</p>
            </div>
            <button 
              onClick={() => setShowForm(true)}
              className="bg-indigo-600 text-white p-4 rounded-2xl shadow-lg shadow-indigo-200 active:scale-95 transition-transform"
            >
              <Plus size={24} />
            </button>
          </div>
        </div>
      </div>

      {/* Expense List */}
      <div className="space-y-3">
        <div className="flex justify-between items-center px-1">
          <h4 className="font-bold text-slate-700 text-sm">지출 내역</h4>
          <button 
            onClick={exportToCSV}
            className="flex items-center gap-1.5 text-[10px] font-bold text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full hover:bg-indigo-100 transition-colors"
          >
            <Download size={12} />
            Sheet 추출
          </button>
        </div>

        {expenses.length === 0 ? (
          <div className="py-12 text-center bg-white rounded-3xl border border-dashed border-slate-300">
            <Banknote className="mx-auto text-slate-200 mb-2" size={40} />
            <p className="text-sm text-slate-400">등록된 지출 내역이 없습니다</p>
          </div>
        ) : (
          expenses.map((exp) => (
            <div key={exp.id} className="group bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4 animate-fadeIn">
              <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shrink-0 ${
                categories.find(c => c.type === exp.category)?.color
              }`}>
                {categories.find(c => c.type === exp.category)?.icon}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex justify-between items-start">
                  <div className="flex flex-col">
                    <h5 className="font-bold text-slate-800 truncate pr-2">{exp.description}</h5>
                    <div className="flex gap-2 items-center mt-0.5">
                      {exp.expenseDate && (
                        <span className="bg-slate-100 text-slate-500 text-[9px] font-bold px-1.5 py-0.5 rounded-md flex items-center gap-0.5">
                          <Calendar size={8} /> {exp.expenseDate}
                        </span>
                      )}
                      {exp.payer && (
                        <span className="bg-indigo-50 text-indigo-500 text-[9px] font-bold px-1.5 py-0.5 rounded-md flex items-center gap-0.5">
                          <UserIcon size={8} /> {exp.payer}
                        </span>
                      )}
                    </div>
                  </div>
                  <button 
                    onClick={() => removeExpense(exp.id)}
                    className="text-slate-300 hover:text-red-400 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
                <div className="flex justify-between items-end mt-2">
                  <div className="text-[10px] text-slate-400 flex items-center gap-1">
                    {new Date(exp.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    <CloudCheck size={10} className="text-emerald-400 ml-1" />
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-slate-700 leading-none">{formatMoney(exp.amount, exp.currency)}</p>
                    {exp.currency === Currency.VND && (
                      <p className="text-[9px] text-slate-400 mt-1 font-medium">≈ ₩ {Math.round(exp.amount * VND_TO_KRW_RATE).toLocaleString()}</p>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Add Form Drawer */}
      {showForm && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-end justify-center">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] p-6 pb-10 animate-slideUp max-h-[90vh] overflow-y-auto no-scrollbar">
            <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mb-6"></div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Category */}
              <div className="px-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3 block">분류</label>
                <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
                  {categories.map((cat) => (
                    <button
                      key={cat.type}
                      type="button"
                      onClick={() => setCategory(cat.type)}
                      className={`min-w-[70px] py-2 px-1 rounded-xl flex flex-col items-center justify-center gap-1 transition-all border-2 ${
                        category === cat.type 
                          ? 'border-indigo-600 bg-indigo-50 text-indigo-600' 
                          : 'border-transparent bg-slate-50 text-slate-400'
                      }`}
                    >
                      <span className="text-base">{cat.icon}</span>
                      <span className="text-[9px] font-black whitespace-nowrap">{cat.type}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Amount & Currency */}
              <div className="space-y-4 px-2">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-xs font-black text-slate-800 uppercase tracking-widest block">금액 (Amount)</label>
                  <div className="flex bg-slate-200 rounded-xl p-1 shadow-inner border border-slate-300 scale-110 origin-right">
                    <button
                      type="button"
                      onClick={() => setCurrency(Currency.VND)}
                      className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${currency === Currency.VND ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500'}`}
                    >VND</button>
                    <button
                      type="button"
                      onClick={() => setCurrency(Currency.KRW)}
                      className={`px-4 py-1.5 text-[10px] font-black rounded-lg transition-all ${currency === Currency.KRW ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500'}`}
                    >KRW</button>
                  </div>
                </div>

                <div className="bg-slate-50 p-5 rounded-3xl border-2 border-slate-200 shadow-inner">
                  <input
                    type="number"
                    value={amount}
                    onChange={(e) => setAmount(e.target.value)}
                    placeholder="0"
                    className="bg-transparent border-none w-full text-4xl font-black text-slate-800 focus:ring-0 p-0 placeholder:text-slate-200"
                    required
                  />
                  {currency === Currency.VND && amount && (
                    <p className="mt-2 text-xs font-bold text-indigo-500 bg-indigo-50 px-3 py-1.5 rounded-lg inline-block">
                      ≈ ₩ {Math.round(parseFloat(amount) * VND_TO_KRW_RATE).toLocaleString()}
                    </p>
                  )}
                </div>
              </div>

              <div className="px-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 block">내용</label>
                <input
                  type="text"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder="지출 내역 (예: 점심 식사)"
                  className="w-full bg-slate-50 p-4 rounded-2xl border-none text-slate-800 font-medium focus:ring-2 focus:ring-indigo-100 shadow-sm"
                  required
                />
              </div>

              <div className="px-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 block">날짜 (선택 사항)</label>
                <div className="flex overflow-x-auto no-scrollbar gap-2 pb-2">
                  {EXPENSE_DATES.map(date => (
                    <button
                      key={date}
                      type="button"
                      onClick={() => setSelectedDate(selectedDate === date ? undefined : date)}
                      className={`px-5 py-2.5 rounded-xl text-xs font-bold transition-all border shrink-0 ${
                        selectedDate === date 
                        ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                        : 'bg-white border-slate-200 text-slate-500'
                      }`}
                    >
                      {date}
                    </button>
                  ))}
                </div>
              </div>

              <div className="px-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 block">지출인 (선택 사항)</label>
                <div className="flex overflow-x-auto no-scrollbar gap-2 pb-2">
                  {PAYERS.map(payer => (
                    <button
                      key={payer}
                      type="button"
                      onClick={() => setSelectedPayer(selectedPayer === payer ? undefined : payer)}
                      className={`px-5 py-2.5 rounded-xl text-xs font-bold transition-all border shrink-0 ${
                        selectedPayer === payer 
                        ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                        : 'bg-white border-slate-200 text-slate-500'
                      }`}
                    >
                      {payer}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex gap-4 pt-6 px-2">
                <button
                  type="button"
                  onClick={() => setShowForm(false)}
                  className="flex-1 py-4 text-slate-400 font-bold hover:bg-slate-50 rounded-2xl transition-colors"
                >취소</button>
                <button
                  type="submit"
                  className="flex-1 py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-xl shadow-indigo-100 flex items-center justify-center gap-2 active:scale-95 transition-transform"
                >
                  <CloudUpload size={18} />
                  저장 및 동기화
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ExpenseTab;

import React, { useState, useEffect } from 'react';
import { Dices, Users, UserPlus, Lightbulb, Send, Trash2, RotateCcw, Sparkles, HelpCircle, Gift, Bomb, Ghost } from 'lucide-react';
import { PAYERS } from '../constants';
import { GameIdea, User } from '../types';

interface GamesTabProps {
  gameIdeas: GameIdea[];
  onUpdateIdeas: (ideas: GameIdea[]) => void;
  user: User;
}

type GameMode = 'MENU' | 'TEAM_SPLIT' | 'PICK_N';

interface GameSlot {
  id: number;
  memberName?: string;
  role: string;
  revealed: boolean;
  color: string;
}

const GamesTab: React.FC<GamesTabProps> = ({ gameIdeas, onUpdateIdeas, user }) => {
  const [mode, setMode] = useState<GameMode>('MENU');
  const [newIdea, setNewIdea] = useState('');
  const [pickCount, setPickCount] = useState<number>(1);
  const [slots, setSlots] = useState<GameSlot[]>([]);
  const [isAllRevealed, setIsAllRevealed] = useState(false);

  // 게임 초기화: 팀 나누기
  const initTeamGame = (teamSize: 2 | 3) => {
    const shuffledMembers = [...PAYERS].sort(() => Math.random() - 0.5);
    const newSlots: GameSlot[] = [];

    if (teamSize === 3) {
      // 3:3 팀 나누기
      const roles = ['TEAM A', 'TEAM A', 'TEAM A', 'TEAM B', 'TEAM B', 'TEAM B'];
      const shuffledRoles = roles.sort(() => Math.random() - 0.5);
      shuffledMembers.forEach((name, i) => {
        newSlots.push({
          id: i,
          memberName: name,
          role: shuffledRoles[i],
          revealed: false,
          color: shuffledRoles[i] === 'TEAM A' ? 'bg-blue-500' : 'bg-rose-500'
        });
      });
    } else {
      // 2:2:2 팀 나누기
      const roles = ['RED', 'RED', 'BLUE', 'BLUE', 'GREEN', 'GREEN'];
      const shuffledRoles = roles.sort(() => Math.random() - 0.5);
      const colors = { RED: 'bg-red-500', BLUE: 'bg-blue-500', GREEN: 'bg-emerald-500' };
      shuffledMembers.forEach((name, i) => {
        newSlots.push({
          id: i,
          memberName: name,
          role: shuffledRoles[i],
          revealed: false,
          color: colors[shuffledRoles[i] as keyof typeof colors]
        });
      });
    }
    setSlots(newSlots);
    setIsAllRevealed(false);
    setMode('TEAM_SPLIT');
  };

  // 게임 초기화: N명 뽑기
  const initPickGame = () => {
    const shuffledMembers = [...PAYERS].sort(() => Math.random() - 0.5);
    const newSlots: GameSlot[] = [];
    const roles = new Array(6).fill('SAFE');
    for(let i=0; i<pickCount; i++) roles[i] = 'SELECTED';
    const shuffledRoles = roles.sort(() => Math.random() - 0.5);

    shuffledMembers.forEach((name, i) => {
      newSlots.push({
        id: i,
        memberName: name,
        role: shuffledRoles[i],
        revealed: false,
        color: shuffledRoles[i] === 'SELECTED' ? 'bg-amber-500' : 'bg-slate-400'
      });
    });
    setSlots(newSlots);
    setIsAllRevealed(false);
    setMode('PICK_N');
  };

  const handleSlotClick = (id: number) => {
    setSlots(prev => prev.map(s => s.id === id ? { ...s, revealed: true } : s));
  };

  const revealAll = () => {
    setSlots(prev => prev.map(s => ({ ...s, revealed: true })));
    setIsAllRevealed(true);
  };

  const handleAddIdea = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newIdea.trim()) return;
    const idea: GameIdea = {
      id: Math.random().toString(36).substr(2, 9),
      text: newIdea.trim(),
      createdBy: user.name,
      timestamp: Date.now()
    };
    onUpdateIdeas([...gameIdeas, idea]);
    setNewIdea('');
  };

  const removeIdea = (id: string) => {
    onUpdateIdeas(gameIdeas.filter(i => i.id !== id));
  };

  return (
    <div className="p-4 space-y-6">
      {mode === 'MENU' ? (
        <section className="space-y-4">
          <div className="flex items-center gap-2 mb-2 px-1">
            <div className="w-8 h-8 bg-indigo-100 text-indigo-600 rounded-lg flex items-center justify-center">
              <Dices size={18} />
            </div>
            <h3 className="font-bold text-slate-800">게임 모드 선택</h3>
          </div>

          <div className="grid grid-cols-1 gap-3">
            <button 
              onClick={() => initTeamGame(3)}
              className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex items-center gap-4 active:scale-95 transition-all text-left"
            >
              <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center shrink-0">
                <Users size={24} />
              </div>
              <div>
                <span className="block text-sm font-black text-slate-800">3:3 팀 나누기</span>
                <span className="text-[10px] text-slate-400 font-medium">카드를 뒤집어 블루/로즈 팀을 결정하세요</span>
              </div>
            </button>

            <button 
              onClick={() => initTeamGame(2)}
              className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex items-center gap-4 active:scale-95 transition-all text-left"
            >
              <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center shrink-0">
                <Sparkles size={24} />
              </div>
              <div>
                <span className="block text-sm font-black text-slate-800">2:2:2 팀 나누기</span>
                <span className="text-[10px] text-slate-400 font-medium">세 개의 팀으로 공평하게 멤버를 나눕니다</span>
              </div>
            </button>

            <div className="bg-white p-5 rounded-3xl border border-slate-200 shadow-sm space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center shrink-0">
                  <Ghost size={24} />
                </div>
                <div className="flex-1">
                  <span className="block text-sm font-black text-slate-800">N명 랜덤 뽑기</span>
                  <div className="flex gap-2 mt-2">
                    {[1, 2, 3].map(n => (
                      <button
                        key={n}
                        onClick={() => setPickCount(n)}
                        className={`flex-1 py-1 rounded-lg text-xs font-black border transition-all ${pickCount === n ? 'bg-amber-500 border-amber-500 text-white' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                      >
                        {n}명
                      </button>
                    ))}
                  </div>
                </div>
              </div>
              <button 
                onClick={initPickGame}
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-sm active:scale-95 transition-all"
              >
                당첨 게임 시작하기
              </button>
            </div>
          </div>
        </section>
      ) : (
        /* 인터랙티브 게임 스테이지 */
        <section className="animate-fadeIn space-y-6">
          <div className="flex justify-between items-center bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
            <button onClick={() => setMode('MENU')} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
              <RotateCcw size={20} />
            </button>
            <div className="text-center">
              <h4 className="text-xs font-black text-indigo-600 uppercase tracking-widest">
                {mode === 'TEAM_SPLIT' ? '팀 나누기 진행 중' : `${pickCount}명 뽑기 진행 중`}
              </h4>
              <p className="text-[10px] text-slate-400 font-bold">각자의 이름이 적힌 카드를 터치하세요!</p>
            </div>
            <button onClick={revealAll} className="p-2 text-indigo-500 font-black text-[10px] uppercase">모두 공개</button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            {slots.map((slot) => (
              <div 
                key={slot.id}
                onClick={() => !slot.revealed && handleSlotClick(slot.id)}
                className={`relative h-32 rounded-[2rem] cursor-pointer transition-all duration-500 perspective-1000 ${slot.revealed ? '[transform:rotateY(180deg)]' : ''}`}
                style={{ transformStyle: 'preserve-3d' }}
              >
                {/* 카드 앞면 (이름 표시) */}
                <div className="absolute inset-0 bg-white border-2 border-indigo-100 shadow-md rounded-[2rem] flex flex-col items-center justify-center gap-2 [backface-visibility:hidden]">
                  <div className="w-10 h-10 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-400">
                    <HelpCircle size={20} />
                  </div>
                  <span className="text-sm font-black text-slate-700">{slot.memberName}</span>
                </div>

                {/* 카드 뒷면 (결과 표시) */}
                <div className={`absolute inset-0 ${slot.color} text-white shadow-xl rounded-[2rem] flex flex-col items-center justify-center gap-1 [backface-visibility:hidden] [transform:rotateY(180deg)] border-4 border-white/20`}>
                  {mode === 'PICK_N' ? (
                    slot.role === 'SELECTED' ? <Bomb size={24} className="animate-bounce" /> : <Gift size={24} />
                  ) : (
                    <Users size={24} />
                  )}
                  <span className="text-[10px] font-black tracking-widest opacity-80 uppercase">{slot.role}</span>
                  <span className="text-xs font-bold">{slot.memberName}</span>
                </div>
              </div>
            ))}
          </div>

          {isAllRevealed && (
            <div className="bg-indigo-600 text-white p-5 rounded-3xl shadow-xl animate-scaleIn text-center">
              <p className="text-xs font-bold opacity-80 mb-1">모든 결과가 확인되었습니다!</p>
              <h5 className="text-lg font-black tracking-tight">게임을 다시 하시겠습니까?</h5>
              <button 
                onClick={() => setMode('MENU')}
                className="mt-4 bg-white text-indigo-600 px-6 py-2.5 rounded-xl font-black text-sm active:scale-95 transition-all"
              >
                처음으로 돌아가기
              </button>
            </div>
          )}
        </section>
      )}

      {/* 2. Brainstorming Memo Section */}
      <section className="space-y-4 pb-10">
        <div className="flex items-center gap-2 px-1">
          <div className="w-8 h-8 bg-amber-100 text-amber-600 rounded-lg flex items-center justify-center">
            <Lightbulb size={18} />
          </div>
          <h3 className="font-bold text-slate-800">게임 아이디어 메모장</h3>
        </div>

        <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
          <form onSubmit={handleAddIdea} className="p-5 border-b border-slate-100 bg-slate-50/50 flex gap-3">
            <input
              type="text"
              value={newIdea}
              onChange={(e) => setNewIdea(e.target.value)}
              placeholder="여행 가서 할 게임 추천!"
              className="flex-1 bg-white border-none rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-100 shadow-sm font-medium"
            />
            <button 
              type="submit"
              className="bg-indigo-600 text-white p-3.5 rounded-2xl shadow-lg active:scale-95 transition-transform"
            >
              <Send size={20} />
            </button>
          </form>

          <div className="max-h-[400px] overflow-y-auto no-scrollbar p-2">
            {gameIdeas.length === 0 ? (
              <div className="py-16 text-center">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Lightbulb size={24} className="text-slate-200" />
                </div>
                <p className="text-xs text-slate-400 font-bold leading-relaxed">
                  아직 올라온 아이디어가 없어요.<br/>
                  술자리 게임, 버스 안 게임 등을 제안해주세요!
                </p>
              </div>
            ) : (
              <div className="grid grid-cols-1 gap-2">
                {[...gameIdeas].reverse().map((idea) => (
                  <div key={idea.id} className="p-4 bg-indigo-50/30 rounded-2xl border border-indigo-100/50 group">
                    <div className="flex justify-between items-start">
                      <div className="flex-1">
                        <p className="text-sm text-slate-700 font-semibold leading-relaxed mb-2">
                          {idea.text}
                        </p>
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-slate-300 font-medium">
                            {new Date(idea.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </span>
                        </div>
                      </div>
                      <button 
                        onClick={() => removeIdea(idea.id)}
                        className="text-slate-200 hover:text-rose-400 p-2 transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <style>{`
        .perspective-1000 {
          perspective: 1000px;
        }
      `}</style>
    </div>
  );
};

